/**
 * Pack raw JSON bytes into a single-entry `payload.json` ZIP_DEFLATED archive.
 *
 * Mirrors Python `_internal/big_payloads/core.py::_zip_payload`. The
 * `payload.json` entry name is part of the cross-repo contract — gateway
 * and `lambda-models` decode by that exact name.
 */

import { zipSync } from 'fflate'

export function zipPayloadJson(jsonBytes: Uint8Array): Uint8Array {
  return zipSync({ 'payload.json': jsonBytes }, { level: 6 })
}
