/**
 * Final `$ref` envelope POST + REF_* response classifier.
 *
 * Mirrors Python `_internal/big_payloads/core.py::_post_envelope` and
 * `_classify_envelope_response`.
 *
 * Two response modes:
 *   - text   (default) — drain `response.text()`. Suitable for JSON or
 *                        plain-text endpoints.
 *   - binary           — on success drain `response.arrayBuffer()` into
 *                        `bodyBytes`. On error still drain text so the
 *                        REF_* classifier can read the JSON payload.
 *
 * Re-encoding `response.text()` via `TextEncoder` corrupts arbitrary
 * binary bytes (PNG, ZIP, etc.) — `responseKind: 'binary'` exists so
 * callers like `WeatherService.generateImage` can opt into the lossless
 * path even when their request crosses the big-payload threshold.
 */

import { redactPresignedUrl } from './redact'

/** Response shape from the envelope POST — agnostic of caller's deserializer. */
export interface EnvelopeResponse {
  ok: boolean
  status: number
  /** Best-effort response body as text (always populated for non-binary
   *  drains, or for error responses in binary mode). */
  bodyText: string
  /** Best-effort JSON-parsed body, or undefined if not JSON. */
  bodyJson: unknown
  /** Raw bytes when `responseKind: 'binary'` and `ok === true`.
   *  `undefined` for the text path or when the body could not be drained
   *  as bytes (typically because we drained text for error classification). */
  bodyBytes?: Uint8Array
}

export interface PostEnvelopeArgs {
  url: string
  getUrl: string
  authHeaders: Record<string, string>
  /** Extra headers (caller-supplied) to merge with auth. */
  extraHeaders?: Record<string, string>
  /** Per-call timeout (ms). */
  timeoutMs: number
  /** Optional abort signal (caller-supplied). */
  signal?: AbortSignal
  /** How to drain the response body on success. Default `'text'`. */
  responseKind?: 'text' | 'binary'
}

export async function postEnvelope(args: PostEnvelopeArgs): Promise<EnvelopeResponse> {
  // Redact `getUrl` for any debug logging done by the caller —
  // signature query strings are bearer credentials.
  void redactPresignedUrl(args.getUrl)

  const controller = new AbortController()
  const timeoutId = setTimeout(() => controller.abort(), args.timeoutMs)

  // Chain caller signal so external aborts propagate.
  let externalAbortHandler: (() => void) | undefined
  if (args.signal) {
    if (args.signal.aborted) {
      clearTimeout(timeoutId)
      const e = new Error('Request aborted by external signal')
      e.name = 'AbortError'
      throw e
    }
    externalAbortHandler = () => controller.abort()
    args.signal.addEventListener('abort', externalAbortHandler, { once: true })
  }

  let response: Response
  try {
    response = await fetch(args.url, {
      method: 'POST',
      headers: {
        ...args.authHeaders,
        ...(args.extraHeaders ?? {}),
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ $ref: args.getUrl }),
      signal: controller.signal,
    })
  } finally {
    clearTimeout(timeoutId)
    if (args.signal && externalAbortHandler) {
      args.signal.removeEventListener('abort', externalAbortHandler)
    }
  }

  // Body draining: on success in binary mode we want raw bytes; otherwise
  // text (plus a JSON parse attempt) is enough. Errors always drain as text
  // so the REF_* classifier can read `{code: 'REF_*'}` payloads.
  if (args.responseKind === 'binary' && response.ok) {
    const buf = await safeReadArrayBuffer(response)
    return {
      ok: true,
      status: response.status,
      bodyText: '',
      bodyJson: undefined,
      bodyBytes: buf,
    }
  }

  const bodyText = await safeReadText(response)
  let bodyJson: unknown
  try {
    bodyJson = bodyText ? JSON.parse(bodyText) : undefined
  } catch {
    bodyJson = undefined
  }

  return {
    ok: response.ok,
    status: response.status,
    bodyText,
    bodyJson,
  }
}

/** Return `(code, message)` if the envelope POST returned a `REF_*` error.
 *
 * `null` means the response is either a success the caller can keep, or a
 * non-REF error left for the caller's existing error handling.
 *
 * Mirrors Python `_classify_envelope_response`.
 */
export function classifyEnvelopeResponse(
  resp: EnvelopeResponse,
): { code: string; message: string } | null {
  if (resp.ok) return null
  if (!(resp.status >= 400 && resp.status < 600)) return null
  if (!resp.bodyJson || typeof resp.bodyJson !== 'object' || Array.isArray(resp.bodyJson)) {
    return null
  }
  const body = resp.bodyJson as Record<string, unknown>
  const code = body.code
  if (typeof code !== 'string' || !code.startsWith('REF_')) return null
  let message = ''
  const m = body.message
  const e = body.error
  if (typeof m === 'string' && m) message = m
  else if (typeof e === 'string' && e) message = e
  else message = resp.bodyText
  return { code, message }
}

async function safeReadText(response: Response): Promise<string> {
  try {
    return await response.text()
  } catch {
    return ''
  }
}

async function safeReadArrayBuffer(response: Response): Promise<Uint8Array> {
  try {
    return new Uint8Array(await response.arrayBuffer())
  } catch {
    return new Uint8Array(0)
  }
}
