/**
 * S3 PUT of zip bytes to a presigned upload URL — no auth headers.
 *
 * Mirrors Python `_internal/big_payloads/core.py::_put_zip_to_s3`. The
 * gateway signs `Content-Type` and `Content-Length` via `signableHeaders`;
 * mismatched bytes or Content-Type yield S3 `SignatureDoesNotMatch`.
 *
 * Bounded retry on transient 5xx; 4xx is fatal and re-uploading the same
 * bytes won't fix it. Critically: never sends X-Api-Key or any other
 * customer auth — S3 would 403 on it, and even on success the request
 * would leak the bearer to AWS.
 */

import { BigPayloadUploadError } from '../../errors'
import { MAX_PUT_RETRIES, S3_PUT_TIMEOUT_MS } from './constants'

export async function putZipToS3(uploadUrl: string, zipBytes: Uint8Array): Promise<void> {
  let lastStatus: number | undefined
  let lastBody = ''
  let lastTransport: string | undefined

  for (let attempt = 1; attempt <= MAX_PUT_RETRIES + 1; attempt++) {
    const controller = new AbortController()
    const timeoutId = setTimeout(() => controller.abort(), S3_PUT_TIMEOUT_MS)

    let response: Response
    try {
      response = await fetch(uploadUrl, {
        method: 'PUT',
        // No auth — explicit. Only Content-Type, which is signed by the
        // gateway via `signableHeaders`.
        headers: { 'Content-Type': 'application/zip' },
        // Fetch derives Content-Length from the Uint8Array body in all
        // supported runtimes (Node 18+, CF Workers, browser). Cast via
        // BodyInit because TS 5.7 narrowed `Uint8Array<ArrayBufferLike>`
        // out of the union; runtime accepts it.
        body: zipBytes as unknown as BodyInit,
        signal: controller.signal,
      })
    } catch (err) {
      // Never stringify a fetch error — its message can include the full
      // URL with signature query string. Class name alone is sufficient.
      lastTransport = err instanceof Error ? err.constructor.name : 'unknown'
      continue
    } finally {
      clearTimeout(timeoutId)
    }

    if (response.ok) return

    lastStatus = response.status
    lastBody = await safeReadText(response)

    // 5xx is transient → retry; 4xx (signature/policy) is fatal.
    if (response.status >= 500 && response.status < 600 && attempt <= MAX_PUT_RETRIES) {
      continue
    }
    break
  }

  if (lastStatus !== undefined) {
    if (lastBody.includes('SignatureDoesNotMatch')) {
      throw new BigPayloadUploadError(
        'S3 PUT signature mismatch — byte-count or Content-Type drift between ' +
          'presign and PUT; recompute zip and retry',
        { statusCode: lastStatus, responseBody: lastBody },
      )
    }
    throw new BigPayloadUploadError(`S3 PUT failed: ${lastStatus}`, {
      statusCode: lastStatus,
      responseBody: lastBody,
    })
  }

  // Transport failures: do not surface the underlying error (its message
  // can include the signed URL). Class name alone — matches Python's
  // `from None` discipline.
  throw new BigPayloadUploadError(
    `S3 PUT failed at transport layer: ${lastTransport ?? 'unknown'}`,
  )
}

async function safeReadText(response: Response): Promise<string> {
  try {
    return await response.text()
  } catch {
    return ''
  }
}
