/**
 * Env-var resolution for big-payload config.
 *
 * Resolution order (matches Python `_is_enabled` / `_threshold_bytes` plus
 * the SDK's universal Worker/Node pattern):
 *   1. Explicit constructor override (`InfraredClientConfig.bigPayloads`).
 *   2. Worker `env` binding (`INFRARED_BIG_PAYLOADS_ENABLED` /
 *      `INFRARED_BIG_PAYLOADS_THRESHOLD_BYTES`).
 *   3. `process.env` (Node only — guarded so Workers don't break).
 *   4. Defaults (`true` / 5 MiB).
 *
 * Read on every call so notebook users can flip the kill-switch mid-session
 * without re-importing — matches Python.
 */

import { ENV_ENABLED, ENV_THRESHOLD, THRESHOLD_DEFAULT_BYTES } from './constants'

/** Bindings carrying the two big-payload env vars. */
export interface BigPayloadEnvBindings {
  INFRARED_BIG_PAYLOADS_ENABLED?: string
  INFRARED_BIG_PAYLOADS_THRESHOLD_BYTES?: string
}

/** Resolved big-payload runtime config. */
export interface BigPayloadConfig {
  /** Whether the envelope path is allowed. Default `true`. */
  enabled: boolean
  /** Cut-over threshold in bytes. Default 5 MiB. */
  thresholdBytes: number
  /** Bare gateway URL for `/uploads/presign`. Set per service. */
  gatewayBaseUrl: string
}

/** Constructor-time overrides (frozen — short-circuit env reads). */
export interface BigPayloadOverride {
  enabled?: boolean
  thresholdBytes?: number
}

function readEnv(env: BigPayloadEnvBindings | undefined, key: string): string | undefined {
  if (env) {
    const v = (env as Record<string, unknown>)[key]
    if (typeof v === 'string') return v
  }
  const proc = (globalThis as { process?: { env?: Record<string, string | undefined> } }).process
  return proc?.env?.[key]
}

/** Read the kill-switch. Constructor override > env > default `true`. */
export function readEnabled(
  env: BigPayloadEnvBindings | undefined,
  override: boolean | undefined,
): boolean {
  if (override !== undefined) return override
  const raw = readEnv(env, ENV_ENABLED)
  if (raw === undefined) return true
  return raw.trim().toLowerCase() === 'true'
}

/** Read the threshold. Constructor override > env > default 5 MiB.
 * Malformed env values fall back to the default. */
export function readThresholdBytes(
  env: BigPayloadEnvBindings | undefined,
  override: number | undefined,
): number {
  if (override !== undefined && Number.isFinite(override) && override > 0) return override
  const raw = readEnv(env, ENV_THRESHOLD)
  if (raw === undefined) return THRESHOLD_DEFAULT_BYTES
  const parsed = Number.parseInt(raw.trim(), 10)
  return Number.isFinite(parsed) && parsed > 0 ? parsed : THRESHOLD_DEFAULT_BYTES
}

/**
 * Strip a trailing `/utils` segment from `baseUrl` if present.
 *
 * The big-payload utility presigns at the gateway level
 * (`{gateway}/uploads/presign`), not under `/utils`. Service clients that
 * hold a `/utils`-prefixed `baseUrl` use this helper to derive the bare
 * gateway URL when one isn't explicitly threaded by the parent client.
 * Idempotent on already-bare URLs.
 */
export function deriveGatewayBaseUrl(baseUrl: string): string {
  const trimmed = baseUrl.replace(/\/+$/, '')
  if (trimmed.endsWith('/utils')) {
    return trimmed.slice(0, -'/utils'.length)
  }
  return baseUrl
}
