/**
 * Gateway presign call — `POST {gateway}/uploads/presign`.
 *
 * Mirrors Python `_internal/big_payloads/core.py::_presign` +
 * `_validate_presign_response`. Uses the caller's bearer-auth headers so the
 * gateway can authenticate the customer and apply per-tenant policy.
 * Validates the response shape, scheme, and host of both URLs before
 * returning. Failures are surfaced as `BigPayloadPresignError`.
 */

import { BigPayloadPresignError } from '../../errors'
import { ALLOWED_PRESIGNED_SCHEMES, PRESIGN_TIMEOUT_MS } from './constants'
import { redactPresignedUrl } from './redact'

export interface PresignResult {
  uploadUrl: string
  getUrl: string
}

export interface PresignArgs {
  gatewayBaseUrl: string
  contentLength: number
  authHeaders: Record<string, string>
}

export async function presignUpload(args: PresignArgs): Promise<PresignResult> {
  const url = `${args.gatewayBaseUrl.replace(/\/+$/, '')}/uploads/presign`

  const controller = new AbortController()
  const timeoutId = setTimeout(() => controller.abort(), PRESIGN_TIMEOUT_MS)

  let response: Response
  try {
    response = await fetch(url, {
      method: 'POST',
      headers: {
        ...args.authHeaders,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ content_length: args.contentLength }),
      signal: controller.signal,
    })
  } catch (err) {
    if (err instanceof Error && err.name === 'AbortError') {
      throw new BigPayloadPresignError(
        `Presign call to ${url} timed out after ${PRESIGN_TIMEOUT_MS}ms`,
      )
    }
    const cls = err instanceof Error ? err.constructor.name : 'unknown'
    throw new BigPayloadPresignError(
      `Presign call to ${url} failed at transport layer: ${cls}`,
    )
  } finally {
    clearTimeout(timeoutId)
  }

  if (!response.ok) {
    const body = await safeReadText(response)
    throw new BigPayloadPresignError(
      `Presign call to ${url} returned ${response.status}`,
      { statusCode: response.status, responseBody: body },
    )
  }

  const text = await safeReadText(response)
  let parsed: unknown
  try {
    parsed = JSON.parse(text)
  } catch {
    throw new BigPayloadPresignError('Presign response was not valid JSON', {
      statusCode: response.status,
      responseBody: text,
    })
  }

  if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
    throw new BigPayloadPresignError('Presign response JSON was not an object', {
      statusCode: response.status,
      responseBody: text,
    })
  }

  const data = parsed as Record<string, unknown>
  const uploadUrl = data['upload-url']
  const getUrl = data['get-url']

  if (typeof uploadUrl !== 'string' || typeof getUrl !== 'string') {
    throw new BigPayloadPresignError(
      "Presign response missing 'upload-url' or 'get-url'",
      { statusCode: response.status, responseBody: text },
    )
  }

  // Validate both URLs are HTTPS with a non-empty host. Failure messages
  // do NOT include the raw URL — `responseBody` carries the redacted form
  // so we don't leak the signed credential into exception logs / Sentry.
  for (const [label, raw] of [
    ['upload-url', uploadUrl] as const,
    ['get-url', getUrl] as const,
  ]) {
    let parsedUrl: URL
    try {
      parsedUrl = new URL(raw)
    } catch {
      throw new BigPayloadPresignError(
        `Presign response '${label}' is not a parseable URL`,
        { statusCode: response.status, responseBody: redactPresignedUrl(raw) },
      )
    }
    if (
      !(ALLOWED_PRESIGNED_SCHEMES as readonly string[]).includes(parsedUrl.protocol) ||
      !parsedUrl.host
    ) {
      throw new BigPayloadPresignError(
        `Presign response '${label}' must use HTTPS with a non-empty host`,
        { statusCode: response.status, responseBody: redactPresignedUrl(raw) },
      )
    }
  }

  return { uploadUrl, getUrl }
}

async function safeReadText(response: Response): Promise<string> {
  try {
    return await response.text()
  } catch {
    return ''
  }
}
