/**
 * Auto-switching big-payload POST flow — TypeScript port of
 * Python SDK `_internal/big_payloads/core.py:367-687`.
 *
 * Public entry points:
 *   - `postWithBigPayload`     — JSON body input; threshold compares raw JSON bytes.
 *   - `postZipWithBigPayload`  — already-zipped body; threshold compares zip bytes.
 *
 * Wire flow above threshold:
 *   1. zip(payload.json) — fflate.zipSync (`payload.json` entry).
 *   2. POST `{gateway}/uploads/presign` body `{content_length: N}`,
 *      auth headers, HTTPS-only validation of `upload-url`/`get-url`.
 *   3. PUT zip bytes to `upload-url` with `Content-Type: application/zip`,
 *      no auth headers, bounded 5xx retry.
 *   4. POST original endpoint with body `{"$ref": getUrl}`, auth headers.
 *   5. If response is `REF_EXPIRED`: re-presign + re-PUT + re-POST,
 *      up to `MAX_REF_EXPIRED_RETRIES`. Other `REF_*` codes throw
 *      `BigPayloadFetchError(code, message)`. Final exhaustion throws
 *      `RefExpiredRetryExhausted`.
 *
 * Below threshold (or when disabled): the inline path delegates back to a
 * caller-supplied function that performs the regular POST. This keeps the
 * existing HttpClient retry/backoff/Retry-After semantics in place for the
 * common case; the wrapper only takes over when the envelope is needed.
 */

import {
  BigPayloadFetchError,
  RefExpiredRetryExhausted,
} from '../../errors'
import type { Logger } from '../../logger'
import { MAX_REF_EXPIRED_RETRIES } from './constants'
import {
  classifyEnvelopeResponse,
  type EnvelopeResponse,
  postEnvelope,
} from './envelope'
import { presignUpload } from './presign'
import { resolveResponseRef } from './response-ref'
import { putZipToS3 } from './upload'
import { zipPayloadJson } from './zip'

/**
 * Inline POST handler — called for sub-threshold or kill-switched calls.
 *
 * Returns the final parsed JSON response (or the raw text the caller wants
 * to surface). Generic over the response shape so the existing
 * `HttpClient.post<T>` plumbing keeps producing the same return type.
 */
export type InlinePostFn<T> = () => Promise<T>

export interface PostWithBigPayloadArgs<T> {
  /** Final endpoint URL (fully qualified). */
  url: string
  /** Raw JSON body (kebab-case-serialized; whatever the caller would have sent). */
  body: Record<string, unknown>
  /** Auth headers to attach to presign + envelope POST. Must include
   *  `X-Api-Key` and `x-infrared-application` (or whatever the caller uses). */
  authHeaders: Record<string, string>
  /** Caller-supplied non-auth headers (e.g. `Accept: image/png`). Forwarded
   *  to the final envelope POST, mirrors Python `_post_envelope(headers=...)`.
   *  Inline path is the caller's responsibility — set them there directly. */
  extraHeaders?: Record<string, string>
  /** Bare gateway URL (no `/utils`) for the presign call. */
  gatewayBaseUrl: string
  /** Cut-over threshold in bytes. Strict greater-than → envelope path. */
  thresholdBytes: number
  /** Kill switch. `false` forces inline path regardless of size. */
  enabled: boolean
  /** Per-call timeout for the envelope POST (ms). */
  envelopeTimeoutMs: number
  /** Optional abort signal (caller-supplied). */
  signal?: AbortSignal
  /** Inline path — invoked when below threshold or disabled. */
  inline: InlinePostFn<T>
  /** Parser converting the envelope response body text/json/bytes into `T`. */
  parseEnvelope: (resp: EnvelopeResponse) => T
  /** Body draining mode for the envelope POST response.
   *  - `'text'` (default) — drain `response.text()`, expose `bodyText` /
   *    `bodyJson`.
   *  - `'binary'`         — on success drain `arrayBuffer()` into
   *    `bodyBytes`. Use for binary endpoints (PNG / ZIP) where text
   *    re-encoding would corrupt the payload. */
  responseKind?: 'text' | 'binary'
  /** Optional logger. */
  logger?: Logger
}

/** Auto-switching POST: inline below threshold, S3 envelope above. */
export async function postWithBigPayload<T>(args: PostWithBigPayloadArgs<T>): Promise<T> {
  const rawBytes = new TextEncoder().encode(JSON.stringify(args.body))
  const useEnvelope = args.enabled && rawBytes.length > args.thresholdBytes

  if (!useEnvelope) {
    args.logger?.debug({
      event: 'big_payloads_inline',
      enabled: args.enabled,
      raw: rawBytes.length,
      threshold: args.thresholdBytes,
    })
    // Response-side `$ref` unwrap (mirrors Python `_finalize`): even a
    // sub-threshold request can get a large `{"$ref": url}` response back.
    return (await resolveResponseRef(await args.inline(), { signal: args.signal })) as T
  }

  const zipBytes = zipPayloadJson(rawBytes)
  args.logger?.info({
    event: 'big_payloads_envelope',
    raw: rawBytes.length,
    zip: zipBytes.length,
  })

  const result = await runEnvelopeFlow({
    url: args.url,
    zipBytes,
    authHeaders: args.authHeaders,
    extraHeaders: args.extraHeaders,
    gatewayBaseUrl: args.gatewayBaseUrl,
    envelopeTimeoutMs: args.envelopeTimeoutMs,
    signal: args.signal,
    parseEnvelope: args.parseEnvelope,
    responseKind: args.responseKind,
    logger: args.logger,
  })
  return (await resolveResponseRef(result, { signal: args.signal })) as T
}

export interface PostZipWithBigPayloadArgs<T> {
  /** Final endpoint URL. */
  url: string
  /** Already-zipped bytes. Threshold compares this length, not the raw payload. */
  zipBytes: Uint8Array
  /** Auth headers. */
  authHeaders: Record<string, string>
  /** Bare gateway URL. */
  gatewayBaseUrl: string
  /** Threshold in bytes (compares zip length). */
  thresholdBytes: number
  /** Kill switch. */
  enabled: boolean
  /** Inline timeout (ms). */
  inlineTimeoutMs: number
  /** Envelope timeout (ms). */
  envelopeTimeoutMs: number
  /** Optional abort signal. */
  signal?: AbortSignal
  /** Parser converting any response (inline or envelope) to `T`. */
  parseResponse: (status: number, ok: boolean, bodyText: string, bodyJson: unknown) => T
  logger?: Logger
}

/**
 * Auto-switching POST for callers that already produced a zip artifact.
 *
 * Mirrors Python `post_zip_with_big_payload`. Below threshold the call is
 * `POST <url>` with `Content-Type: application/zip` and zip bytes inline.
 * Above threshold the same envelope flow as `postWithBigPayload` is used.
 */
export async function postZipWithBigPayload<T>(
  args: PostZipWithBigPayloadArgs<T>,
): Promise<T> {
  const useEnvelope = args.enabled && args.zipBytes.length > args.thresholdBytes

  if (!useEnvelope) {
    args.logger?.debug({
      event: 'big_payloads_inline_zip',
      enabled: args.enabled,
      zip: args.zipBytes.length,
      threshold: args.thresholdBytes,
    })
    const inlineResult = await inlineZipPost({
      url: args.url,
      zipBytes: args.zipBytes,
      authHeaders: args.authHeaders,
      timeoutMs: args.inlineTimeoutMs,
      signal: args.signal,
      parseResponse: args.parseResponse,
    })
    return (await resolveResponseRef(inlineResult, { signal: args.signal })) as T
  }

  args.logger?.info({
    event: 'big_payloads_envelope_zip',
    zip: args.zipBytes.length,
    threshold: args.thresholdBytes,
  })

  const result = await runEnvelopeFlow({
    url: args.url,
    zipBytes: args.zipBytes,
    authHeaders: args.authHeaders,
    gatewayBaseUrl: args.gatewayBaseUrl,
    envelopeTimeoutMs: args.envelopeTimeoutMs,
    signal: args.signal,
    parseEnvelope: (resp) =>
      args.parseResponse(resp.status, resp.ok, resp.bodyText, resp.bodyJson),
    logger: args.logger,
  })
  return (await resolveResponseRef(result, { signal: args.signal })) as T
}

// ---------------------------------------------------------------------------
// Internals
// ---------------------------------------------------------------------------

interface EnvelopeFlowArgs<T> {
  url: string
  zipBytes: Uint8Array
  authHeaders: Record<string, string>
  extraHeaders?: Record<string, string>
  gatewayBaseUrl: string
  envelopeTimeoutMs: number
  signal?: AbortSignal
  parseEnvelope: (resp: EnvelopeResponse) => T
  responseKind?: 'text' | 'binary'
  logger?: Logger
}

async function runEnvelopeFlow<T>(args: EnvelopeFlowArgs<T>): Promise<T> {
  // Initial: presign → PUT → envelope POST.
  let presigned = await presignUpload({
    gatewayBaseUrl: args.gatewayBaseUrl,
    contentLength: args.zipBytes.length,
    authHeaders: args.authHeaders,
  })
  await putZipToS3(presigned.uploadUrl, args.zipBytes)
  let response = await postEnvelope({
    url: args.url,
    getUrl: presigned.getUrl,
    authHeaders: args.authHeaders,
    extraHeaders: args.extraHeaders,
    timeoutMs: args.envelopeTimeoutMs,
    signal: args.signal,
    responseKind: args.responseKind,
  })

  // REF_EXPIRED retry loop.
  for (let attempt = 1; attempt <= MAX_REF_EXPIRED_RETRIES; attempt++) {
    const outcome = classifyEnvelopeResponse(response)
    if (outcome === null) return args.parseEnvelope(response)

    if (outcome.code !== 'REF_EXPIRED') {
      throw new BigPayloadFetchError(outcome.code, outcome.message, {
        statusCode: response.status,
        responseBody: response.bodyText,
      })
    }

    args.logger?.warn({
      event: 'big_payloads_ref_expired',
      attempt,
      max: MAX_REF_EXPIRED_RETRIES,
    })
    presigned = await presignUpload({
      gatewayBaseUrl: args.gatewayBaseUrl,
      contentLength: args.zipBytes.length,
      authHeaders: args.authHeaders,
    })
    await putZipToS3(presigned.uploadUrl, args.zipBytes)
    response = await postEnvelope({
      url: args.url,
      getUrl: presigned.getUrl,
      authHeaders: args.authHeaders,
      extraHeaders: args.extraHeaders,
      timeoutMs: args.envelopeTimeoutMs,
      signal: args.signal,
      responseKind: args.responseKind,
    })
  }

  // Final outcome after retry budget exhausted.
  const finalOutcome = classifyEnvelopeResponse(response)
  if (finalOutcome === null) return args.parseEnvelope(response)
  if (finalOutcome.code === 'REF_EXPIRED') {
    throw new RefExpiredRetryExhausted(
      `REF_EXPIRED after ${MAX_REF_EXPIRED_RETRIES} retries: ${finalOutcome.message}`,
      { statusCode: response.status, responseBody: response.bodyText },
    )
  }
  throw new BigPayloadFetchError(finalOutcome.code, finalOutcome.message, {
    statusCode: response.status,
    responseBody: response.bodyText,
  })
}

interface InlineZipPostArgs<T> {
  url: string
  zipBytes: Uint8Array
  authHeaders: Record<string, string>
  timeoutMs: number
  signal?: AbortSignal
  parseResponse: (status: number, ok: boolean, bodyText: string, bodyJson: unknown) => T
}

async function inlineZipPost<T>(args: InlineZipPostArgs<T>): Promise<T> {
  const controller = new AbortController()
  const timeoutId = setTimeout(() => controller.abort(), args.timeoutMs)

  let externalAbortHandler: (() => void) | undefined
  if (args.signal) {
    if (args.signal.aborted) {
      clearTimeout(timeoutId)
      const e = new Error('Request aborted by external signal')
      e.name = 'AbortError'
      throw e
    }
    externalAbortHandler = () => controller.abort()
    args.signal.addEventListener('abort', externalAbortHandler, { once: true })
  }

  let response: Response
  try {
    response = await fetch(args.url, {
      method: 'POST',
      headers: {
        ...args.authHeaders,
        'Content-Type': 'application/zip',
      },
      // Cast via BodyInit — TS 5.7 narrowed Uint8Array<ArrayBufferLike>
      // out of the union; runtime accepts it across Node/Workers/browser.
      body: args.zipBytes as unknown as BodyInit,
      signal: controller.signal,
    })
  } finally {
    clearTimeout(timeoutId)
    if (args.signal && externalAbortHandler) {
      args.signal.removeEventListener('abort', externalAbortHandler)
    }
  }

  const bodyText = await safeReadText(response)
  let bodyJson: unknown
  try {
    bodyJson = bodyText ? JSON.parse(bodyText) : undefined
  } catch {
    bodyJson = undefined
  }

  return args.parseResponse(response.status, response.ok, bodyText, bodyJson)
}

async function safeReadText(response: Response): Promise<string> {
  try {
    return await response.text()
  } catch {
    return ''
  }
}
